func init() {
	prometheus.MustRegister(requestCounter)
	prometheus.MustRegister(requestDuration)
	prometheus.MustRegister(activeUsers)
	prometheus.MustRegister(requestSize)
	prometheus.MustRegister(responseSize)
	prometheus.MustRegister(userOperations)
	prometheus.MustRegister(userSessionDuration)
	prometheus.MustRegister(perUserRequestRate)
	prometheus.MustRegister(userErrors)
	prometheus.MustRegister(customUserMetric)
}

func trackRequest(userID, endpoint, method, status string, duration float64, reqSize, respSize int64) {
	requestCounter.WithLabelValues(userID, endpoint, method, status).Inc()
	requestDuration.WithLabelValues(userID, endpoint, method).Observe(duration)
	requestSize.WithLabelValues(userID, endpoint, "application/json").Observe(float64(reqSize))
	responseSize.WithLabelValues(userID, endpoint, "application/json").Observe(float64(respSize))
}

func trackUserOperation(userID, operationType, resourceID, result string) {
	userOperations.WithLabelValues(userID, operationType, resourceID, result).Inc()
}

func trackUserSession(userID, sessionID, deviceType string, duration float64) {
	userSessionDuration.WithLabelValues(userID, sessionID, deviceType).Observe(duration)
}

func trackUserError(userID, errorType, errorCode, endpoint string) {
	userErrors.WithLabelValues(userID, errorType, errorCode, endpoint).Inc()
}

func setActiveUser(userID, sessionID string, active bool) {
	if active {
		activeUsers.WithLabelValues(userID, sessionID).Set(1)
	} else {
		activeUsers.WithLabelValues(userID, sessionID).Set(0)
	}
}

func setCustomMetric(userID, label1, label2, label3 string, value float64) {
	customUserMetric.WithLabelValues(userID, label1, label2, label3).Set(value)
}

func apiHandler(w http.ResponseWriter, r *http.Request) {
	start := time.Now()

	userID := r.URL.Query().Get("user_id")
	if userID == "" {
		userID = "anonymous"
	}

	endpoint := r.URL.Path
	method := r.Method
	sessionID := r.URL.Query().Get("session_id")
	if sessionID == "" {
		sessionID = fmt.Sprintf("session_%d", rand.Intn(1000))
	}

	setActiveUser(userID, sessionID, true)

	duration := time.Duration(rand.Intn(1000)) * time.Millisecond
	time.Sleep(duration)

	status := "200"
	if rand.Float64() < 0.1 {
		status = "500"
		trackUserError(userID, "internal_error", "ERR_500", endpoint)
	} else if rand.Float64() < 0.05 {
		status = "404"
		trackUserError(userID, "not_found", "ERR_404", endpoint)
	}

	reqSize := int64(rand.Intn(10000))
	respSize := int64(rand.Intn(50000))

	trackRequest(userID, endpoint, method, status, time.Since(start).Seconds(), reqSize, respSize)

	operationType := r.URL.Query().Get("operation")
	if operationType != "" {
		resourceID := r.URL.Query().Get("resource_id")
		if resourceID == "" {
			resourceID = fmt.Sprintf("resource_%d", rand.Intn(100))
		}
		result := "success"
		if status != "200" {
			result = "failure"
		}
		trackUserOperation(userID, operationType, resourceID, result)
	}

	perUserRequestRate.WithLabelValues(userID, endpoint).Set(float64(rand.Intn(100)))

	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Request processed for user: %s, endpoint: %s\n", userID, endpoint)
}

func customMetricHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	label1 := r.URL.Query().Get("label1")
	label2 := r.URL.Query().Get("label2")
	label3 := r.URL.Query().Get("label3")

	if userID == "" || label1 == "" || label2 == "" || label3 == "" {
		http.Error(w, "Missing required parameters: user_id, label1, label2, label3", http.StatusBadRequest)
		return
	}

	value := float64(rand.Intn(1000))
	setCustomMetric(userID, label1, label2, label3, value)

	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Custom metric set for user: %s with labels: %s, %s, %s, value: %.2f\n", userID, label1, label2, label3, value)
}

func sessionHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("user_id")
	sessionID := r.URL.Query().Get("session_id")
	deviceType := r.URL.Query().Get("device_type")

	if userID == "" || sessionID == "" || deviceType == "" {
		http.Error(w, "Missing required parameters: user_id, session_id, device_type", http.StatusBadRequest)
		return
	}

	duration := float64(rand.Intn(3600))
	trackUserSession(userID, sessionID, deviceType, duration)

	setActiveUser(userID, sessionID, false)

	w.WriteHeader(http.StatusOK)
	fmt.Fprintf(w, "Session tracked for user: %s, session: %s, duration: %.2f seconds\n", userID, sessionID, duration)
}

func simulateTraffic() {
	users := []string{"user_1", "user_2", "user_3", "user_4", "user_5"}
	endpoints := []string{"/api/data", "/api/users", "/api/products", "/api/orders"}
	operations := []string{"create", "read", "update", "delete"}
	devices := []string{"mobile", "desktop", "tablet"}

	ticker := time.NewTicker(2 * time.Second)
	defer ticker.Stop()

	for range ticker.C {
		userID := users[rand.Intn(len(users))]
		endpoint := endpoints[rand.Intn(len(endpoints))]
		operation := operations[rand.Intn(len(operations))]
		deviceType := devices[rand.Intn(len(devices))]
		sessionID := fmt.Sprintf("session_%s_%d", userID, rand.Intn(10))

		go func() {
			url := fmt.Sprintf("http://localhost:8080%s?user_id=%s&session_id=%s&operation=%s",
				endpoint, userID, sessionID, operation)
			http.Get(url)
		}()

		if rand.Float64() < 0.3 {
			go func() {
				url := fmt.Sprintf("http://localhost:8080/custom?user_id=%s&label1=region_%d&label2=product_%d&label3=version_%d",
					userID, rand.Intn(5), rand.Intn(10), rand.Intn(3))
				http.Get(url)
			}()
		}

		if rand.Float64() < 0.2 {
			go func() {
				url := fmt.Sprintf("http://localhost:8080/session?user_id=%s&session_id=%s&device_type=%s",
					userID, sessionID, deviceType)
				http.Get(url)
			}()
		}
	}
}

func main() {
	http.HandleFunc("/api/", apiHandler)
	http.HandleFunc("/custom", customMetricHandler)
	http.HandleFunc("/session", sessionHandler)
	http.Handle("/metrics", promhttp.Handler())

	go simulateTraffic()

	log.Println("Starting server on :8080")
	log.Println("Metrics available at http://localhost:8080/metrics")
	log.Println("API endpoints:")
	log.Println("  - /api/* (with query params: user_id, session_id, operation, resource_id)")
	log.Println("  - /custom (with query params: user_id, label1, label2, label3)")
	log.Println("  - /session (with query params: user_id, session_id, device_type)")
	log.Fatal(http.ListenAndServe(":8080", nil))
}